-- Mettre à jour Export CSV/PDF (ADMIN-05) → promoted
UPDATE ideas SET status = 'promoted', priority = 'haute', category = 'Admin' WHERE title LIKE '%Export%' OR title LIKE '%export%';

-- Mettre à jour Accessibilité RGAA (ACC-01) → promoted
UPDATE ideas SET status = 'promoted', priority = 'haute', category = 'Accessibilité' WHERE title LIKE '%Accessibilit%' OR title LIKE '%RGAA%';

-- Ajouter les entrées journal dans actions_log
INSERT INTO actions_log (project_id, action_type, title, description, author, created_at)
SELECT p.id, 'deployment', 'ADMIN-05 : Export CSV/PDF déployé', 'ExportController PHP avec FPDF — endpoints /mc-api/admin/reports/export?format=csv|pdf opérationnels', 'Manus', NOW()
FROM projects p LIMIT 1;

INSERT INTO actions_log (project_id, action_type, title, description, author, created_at)
SELECT p.id, 'deployment', 'ACC-01 : Audit accessibilité RGAA', '3 écrans React Native enrichis (Login, Register, CreateIncident) + ACCESSIBILITY_AUDIT.md — 146 éléments auditées', 'Manus', NOW()
FROM projects p LIMIT 1;

INSERT INTO actions_log (project_id, action_type, title, description, author, created_at)
SELECT p.id, 'deployment', 'PIPL : Widget Ma Commune métriques live', 'MaCommuneWidget dans le Dashboard PIPL — appel /mc-api/incidents toutes les 2min, KPIs + signalements récents', 'Manus', NOW()
FROM projects p LIMIT 1;

INSERT INTO actions_log (project_id, action_type, title, description, author, created_at)
SELECT p.id, 'deployment', 'fix: CORS dynamique multi-origines Ma Commune', 'CORS_ORIGINS étendu à pipl.netetfix.com — index.php corrigé pour gérer plusieurs origines autorisées dynamiquement', 'Manus', NOW()
FROM projects p LIMIT 1;

